// Normalize input from either trigger
const body = $input.first().json?.body || $input.first().json || {};
const projectId = body.project_id || null;
return [{ json: { projectId, source: projectId ? 'webhook' : 'cron' } }];

// Handle private-to-public transitions for scheduled and over-quota videos
const topics = $input.first().json;
const allTopics = Array.isArray(topics) ? topics : [];
const now = new Date();

// Find scheduled videos whose publish time has passed
const transitionCandidates = allTopics.filter(t => {
  if (t.status === 'scheduled' && t.published_at) {
    return new Date(t.published_at) <= now;
  }
  // Also catch videos stuck in 'publishing' (over-quota private uploads)
  if (t.status === 'publishing') {
    return true;
  }
  return false;
});

// Collect video IDs for analytics pull (all topics with youtube_video_id)
const videoIds = allTopics
  .filter(t => t.youtube_video_id)
  .map(t => t.youtube_video_id);

return [{
  json: {
    allTopics,
    transitionCandidates,
    transitionCount: transitionCandidates.length,
    videoIds,
    videoIdString: videoIds.join(','),
    totalVideos: videoIds.length
  }
}];

// Split transition candidates into individual items
const { transitionCandidates } = $('Process Topics & Transitions').first().json;
return transitionCandidates.map(t => ({ json: t }));

// Build YouTube Analytics API request parameters
const { videoIdString, allTopics } = $('Process Topics & Transitions').first().json;

const now = new Date();
const ninetyDaysAgo = new Date(now.getTime() - 90 * 24 * 60 * 60 * 1000);

const startDate = ninetyDaysAgo.toISOString().split('T')[0];
const endDate = now.toISOString().split('T')[0];

return [{
  json: {
    startDate,
    endDate,
    videoIdString,
    allTopics,
    analyticsUrl: `https://youtubeanalytics.googleapis.com/v2/reports?ids=channel==MINE&startDate=${startDate}&endDate=${endDate}&metrics=views,estimatedMinutesWatched,averageViewDuration,averageViewPercentage,likes,comments,subscribersGained,estimatedRevenue,cpm,impressions&dimensions=video&filters=video==${videoIdString}&sort=-views`
  }
}];

// Parse YouTube Analytics response and map to topic updates
const response = $input.first().json;
const allTopics = $('Build Analytics Query').first().json.allTopics;

// Handle API errors (403 scope issue, empty results, etc.)
if (response.error) {
  const errorCode = response.error.code || 'unknown';
  const errorMsg = response.error.message || JSON.stringify(response.error);
  return [{
    json: {
      updates: [],
      videosUpdated: 0,
      error: true,
      errorCode,
      errorMessage: errorMsg,
      scopeWarning: errorCode === 403 ? 'YouTube OAuth2 credential requires yt-analytics.readonly scope' : null
    }
  }];
}

const rows = response.rows || [];
if (rows.length === 0) {
  return [{ json: { updates: [], videosUpdated: 0, error: false } }];
}

// Column order: videoId, views, estimatedMinutesWatched, averageViewDuration,
// averageViewPercentage, likes, comments, subscribersGained, estimatedRevenue, cpm, impressions
const updates = rows.map(row => {
  const [videoId, views, watchMinutes, avgDuration, avgPct, likes, comments, subsGained, revenue, cpm, impressions] = row;

  // Find matching topic
  const topic = allTopics.find(t => t.youtube_video_id === videoId);
  if (!topic) return null;

  // Format avgDuration (seconds) as M:SS
  const durationMin = Math.floor(avgDuration / 60);
  const durationSec = Math.round(avgDuration % 60);
  const avgViewDuration = `${durationMin}:${String(durationSec).padStart(2, '0')}`;

  // Compute CTR: views / impressions * 100
  const ctr = impressions > 0 ? Math.round((views / impressions) * 10000) / 100 : 0;

  return {
    topicId: topic.id,
    youtubeVideoId: videoId,
    yt_views: views,
    yt_watch_hours: Math.round((watchMinutes / 60) * 100) / 100,
    yt_avg_view_duration: avgViewDuration,
    yt_avg_view_pct: Math.round(avgPct * 100) / 100,
    yt_ctr: ctr,
    yt_impressions: impressions,
    yt_likes: likes,
    yt_comments: comments,
    yt_subscribers_gained: subsGained,
    yt_estimated_revenue: Math.round(revenue * 100) / 100,
    yt_actual_cpm: Math.round(cpm * 100) / 100
  };
}).filter(Boolean);

return [{ json: { updates, videosUpdated: updates.length, error: false } }];

// Split updates into individual items for batch write
const { updates } = $('Parse Analytics Response').first().json;
return updates.map(u => ({ json: u }));

