// Build response for webhook trigger
const videosUpdated = $('Parse Analytics Response').first()?.json?.videosUpdated || 0;
const transitionCount = $('Process Topics & Transitions').first()?.json?.transitionCount || 0;
const error = $('Parse Analytics Response').first()?.json?.error || false;
const scopeWarning = $('Parse Analytics Response').first()?.json?.scopeWarning || null;

return [{
  json: {
    success: !error,
    videos_updated: videosUpdated,
    transitions: transitionCount,
    ...(scopeWarning ? { warning: scopeWarning } : {}),
    ...(error ? { error: $('Parse Analytics Response').first()?.json?.errorMessage } : {})
  }
}];

// AU Retention Analysis — Day-7+ analyzer for published AU videos
// Runs after the daily analytics write. Picks up to 10 AU topics with:
//   country_target = 'AU'
//   yt_views > 0  (analytics ran at least once)
//   published_at < now() - 7 days
//   next_video_directives IS NULL  (not yet analysed)
// Calls Claude Haiku with retention_analyze_au prompt + topic metadata +
// aggregate metrics + script chapter snapshot. Writes the result back
// to topics.next_video_directives. Failures are non-fatal — they're
// recorded in the per-topic results array and the workflow proceeds to
// Build Response unchanged. Costs ~$0.005/topic at Haiku rates.

const SB = $env.SUPABASE_URL;
const SRK = $env.SUPABASE_SERVICE_ROLE_KEY;
const ANON = $env.SUPABASE_ANON_KEY;
const AK = $env.ANTHROPIC_API_KEY;
const sbHeaders = { apikey: ANON || SRK, Authorization: 'Bearer ' + SRK, 'Content-Type': 'application/json' };

const upstream = ($input && $input.first && $input.first().json) || {};

// 1. Discover candidates
const cutoffIso = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString();
const candUrl = `${SB}/rest/v1/topics?country_target=eq.AU&yt_views=gt.0&published_at=lt.${cutoffIso}&next_video_directives=is.null&select=id,seo_title,niche_variant,published_at,yt_avg_view_pct,yt_views,yt_watch_hours,script_json&limit=10`;

let topics = [];
try {
  const r = await fetch(candUrl, { headers: sbHeaders });
  if (r.ok) topics = await r.json();
} catch (e) {
  return [{ json: { ...upstream, au_retention: { status: 'fetch_error', count: 0, error: String(e && e.message || e) } } }];
}

if (!Array.isArray(topics) || topics.length === 0) {
  return [{ json: { ...upstream, au_retention: { status: 'nothing_to_analyze', count: 0 } } }];
}

// 2. Fetch the prompt once
let promptText = '';
try {
  const pr = await fetch(`${SB}/rest/v1/system_prompts?prompt_type=eq.retention_analyze_au&is_active=eq.true&select=prompt_text`, { headers: sbHeaders });
  if (pr.ok) {
    const rows = await pr.json();
    promptText = (Array.isArray(rows) && rows[0] && rows[0].prompt_text) || '';
  }
} catch (_) {}
if (!promptText) {
  return [{ json: { ...upstream, au_retention: { status: 'prompt_missing', count: 0 } } }];
}

// 3. Per-topic: build user message, call Claude, write next_video_directives
function summariseScript(sj) {
  let scenes = [];
  try {
    if (typeof sj === 'string') {
      try { sj = JSON.parse(sj); } catch (_) { return ''; }
    }
    if (Array.isArray(sj)) scenes = sj;
    else if (sj && Array.isArray(sj.scenes)) scenes = sj.scenes;
    else if (sj && Array.isArray(sj.combined_scenes)) scenes = sj.combined_scenes;
  } catch (_) { return ''; }
  if (!scenes.length) return '';
  return scenes.slice(0, 30).map((s, i) => {
    const text = (s && (s.narration_text || s.narration || '')) || '';
    return `Scene ${i + 1}: ${String(text).slice(0, 100).replace(/\s+/g, ' ').trim()}`;
  }).join('\n');
}

const results = [];
for (const t of topics) {
  const chapters = summariseScript(t.script_json) || '(script_json not parseable)';
  const userMsg = [
    '[VIDEO METADATA]',
    `Title: ${t.seo_title || '(unknown)'}`,
    `Sub-niche: ${t.niche_variant || '(unset)'}`,
    `Published: ${t.published_at || '(unknown)'}`,
    '',
    '[AGGREGATE METRICS]',
    `Avg view %: ${t.yt_avg_view_pct == null ? 'unknown' : t.yt_avg_view_pct}`,
    `Views: ${t.yt_views == null ? 0 : t.yt_views}`,
    `Watch hours: ${t.yt_watch_hours == null ? 0 : t.yt_watch_hours}`,
    '',
    '[SCRIPT — first 30 scenes (narration excerpts)]',
    chapters,
    '',
    '[TASK]',
    'Per the retention_analyze_au system prompt, infer hook strength, drop-off hypotheses, AU disclaimer placement issues, and surge moments. We do NOT have per-second retention curves — reason from aggregate metrics + script structure + known AU patterns. Return ONLY this JSON shape, no markdown:',
    '{',
    '  "diagnosis": ["weak_hook" | "setup_too_slow" | "pacing_lull" | "retention_cliff" | "cta_chasm" | "disclaimer_drop"],',
    '  "drop_off_hypotheses": [{"scene_range": "1-5", "reason": "..."}],',
    '  "surge_hypotheses": [{"scene_range": "...", "reason": "..."}],',
    '  "next_video_directives": [{"action": "...", "rationale": "...", "priority": "high" | "med" | "low"}],',
    '  "au_specific_notes": "..."',
    '}'
  ].join('\n');

  let analysis = null;
  let claudeErr = null;
  try {
    const cr = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: { 'x-api-key': AK, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
      body: JSON.stringify({
        model: 'claude-haiku-4-5-20251001',
        max_tokens: 2000,
        system: promptText,
        messages: [{ role: 'user', content: userMsg }]
      })
    });
    if (!cr.ok) {
      claudeErr = `HTTP ${cr.status}: ${(await cr.text()).slice(0, 200)}`;
    } else {
      const cd = await cr.json();
      const txt = (cd.content || []).filter(c => c.type === 'text').map(c => c.text).join('');
      const m = txt.match(/\{[\s\S]*\}/);
      if (m) {
        try { analysis = JSON.parse(m[0]); } catch (e) { claudeErr = 'json_parse_failed: ' + e.message; }
      } else {
        claudeErr = 'no_json_in_response';
      }
    }
  } catch (e) {
    claudeErr = String(e && e.message || e);
  }

  if (!analysis) {
    results.push({ topic_id: t.id, status: 'analyze_failed', error: claudeErr });
    continue;
  }

  try {
    const pr = await fetch(`${SB}/rest/v1/topics?id=eq.${t.id}`, {
      method: 'PATCH',
      headers: { ...sbHeaders, Prefer: 'return=minimal' },
      body: JSON.stringify({ next_video_directives: analysis })
    });
    if (!pr.ok) {
      results.push({ topic_id: t.id, status: 'patch_failed', error: `HTTP ${pr.status}` });
      continue;
    }
    results.push({ topic_id: t.id, status: 'updated' });
  } catch (e) {
    results.push({ topic_id: t.id, status: 'patch_failed', error: String(e && e.message || e) });
  }
}

return [{ json: { ...upstream, au_retention: { status: 'completed', count: results.length, results } } }];
